t this.$http.get(`/${this.resource}/data_table`).then((response) => {\r\n                this.all_customers = response.data.customers\r\n                this.series = response.data.series\r\n            });\r\n\r\n            await this.getRecords()\r\n            await this.filterCustomers()\r\n            await this.loadScroll()\r\n        },\r\n        methods: {\r\n            searchRemoteCustomers(input) {\r\n\r\n                if (input.length > 0) {\r\n\r\n                    this.loading_search = true\r\n                    let parameters = `input=${input}`\r\n\r\n                    this.$http.get(`/documents/data-table/customers?${parameters}`)\r\n                            .then(response => {\r\n                                this.customers = response.data.customers\r\n                                this.loading_search = false\r\n\r\n                                if(this.customers.length == 0){\r\n                                    this.filterCustomers()\r\n                                }\r\n                            })\r\n                } else {\r\n                    this.filterCustomers()\r\n                }\r\n\r\n            },\r\n            filterCustomers() {\r\n                this.customers = this.all_customers\r\n            },\r\n            clickSeeMore(){\r\n                this.see_more = (this.see_more) ? false : true\r\n            },\r\n            initForm(){\r\n\r\n                this.search = {\r\n                    date_of_issue: null,\r\n                    customer_id:null,\r\n                    series:null,\r\n                    number:null,\r\n                    d_start:null,\r\n                    d_end:null,\r\n                }\r\n            },\r\n            changeDocumentType(){\r\n                this.filterSeries();\r\n            },\r\n            customIndex(index) {\r\n                return (this.pagination.per_page * (this.pagination.current_page - 1)) + index + 1\r\n            },\r\n            async getRecordsByFilter(){\r\n\r\n                this.loading_submit = await true\r\n                await this.getRecords()\r\n                this.loading_submit = await false\r\n\r\n            },\r\n            getRecords() {\r\n                return this.$http.get(`/${this.resource}/records?${this.getQueryParameters()}`).then((response) => {\r\n                    this.records = response.data.data\r\n                    this.pagination = response.data.meta\r\n                    this.pagination.per_page = parseInt(response.data.meta.per_page)\r\n                    this.loading_submit = false\r\n                });\r\n\r\n            },\r\n            getQueryParameters() {\r\n                return queryString.stringify({\r\n                    page: this.pagination.current_page,\r\n                    limit: this.limit,\r\n                    ...this.search\r\n                })\r\n            },\r\n            changeClearInput(){\r\n                this.search.value = ''\r\n                // this.getRecords()\r\n            },\r\n            changeDisabledDates() {\r\n                this.search.date_of_issue = null\r\n                if (this.search.d_end < this.search.d_start) {\r\n                    this.search.d_end = this.search.d_start\r\n                }\r\n            },\r\n            changeDateOfIssue(){\r\n                this.search.d_start = null\r\n                this.search.d_end = null\r\n            },\r\n            changeEndDate(){\r\n                this.search.date_of_issue = null\r\n            },\r\n            cleanInputs(){\r\n                this.initForm()\r\n            },\r\n            loadScroll(){\r\n                $(\"#scroll1 div\").width($(\".table\").width());\r\n                $(\"#scroll1\").on(\"scroll\", function(){\r\n                    $(\"#scroll2\").scrollLeft($(this).scrollLeft());\r\n                });\r\n                $(\"#scroll2\").on(\"scroll\", function(){\r\n                    $(\"#scroll1\").sc